document.addEventListener("DOMContentLoaded",function(){const boxes=document.querySelectorAll(".read-more-box");boxes.forEach(box=>{const fullText=box.textContent.trim();const limit=parseInt(box.dataset.limit)||100;if(fullText.length<=limit)return;const truncateAtWord=(str,limit)=>{const trimmed=str.substring(0,limit);return trimmed.substring(0,trimmed.lastIndexOf(" "))};const visibleText=truncateAtWord(fullText,limit);const hiddenText=fullText.substring(visibleText.length);box.innerHTML=`
      <span class="visible-text">${visibleText}</span><span class="dots">...</span><span class="more-text">${hiddenText}</span>
      <span class="read-more-link"> Read More</span>
    `;const readMoreLink=box.querySelector(".read-more-link");const moreText=box.querySelector(".more-text");const dots=box.querySelector(".dots");readMoreLink.addEventListener("click",function(){const isExpanded=moreText.style.display==="inline";moreText.style.display=isExpanded?"none":"inline";dots.style.display=isExpanded?"inline":"none";readMoreLink.textContent=isExpanded?" Read More":" Read Less"})})})